import axiosInstance from './axiosInstance';

export const riskService = {
  getRisks: (params) =>
    axiosInstance.get('/risks', { params })
      .then((res) => res.data.data),
  triggerScan: (companyId) =>
    axiosInstance.post('/risks/scan', { companyId })
      .then((res) => res.data.data),
};
